// examples/05-parallel-animations.ts
function createProject5() {
  const $ = new VideoFlow({
    name: "Parallel Animations",
    width: 1920,
    height: 1080,
    fps: 30,
    backgroundColor: "#0f0f23"
  });
  const line1 = $.addText({
    text: "Design.",
    fontSize: 3,
    fontWeight: 800,
    color: "#ff6b6b",
    position: [0.5, 0.3],
    opacity: 0
  });
  const line2 = $.addText({
    text: "Animate.",
    fontSize: 3,
    fontWeight: 800,
    color: "#4ecdc4",
    position: [0.5, 0.5],
    opacity: 0
  });
  const line3 = $.addText({
    text: "Render.",
    fontSize: 3,
    fontWeight: 800,
    color: "#45b7d1",
    position: [0.5, 0.7],
    opacity: 0
  });
  $.parallel([
    () => {
      line1.animate(
        { opacity: 0, position: [0.3, 0.3] },
        { opacity: 1, position: [0.5, 0.3] },
        { duration: "800ms", easing: "easeOut" }
      );
    },
    () => {
      $.wait("200ms");
      line2.animate(
        { opacity: 0, position: [0.3, 0.5] },
        { opacity: 1, position: [0.5, 0.5] },
        { duration: "800ms", easing: "easeOut" }
      );
    },
    () => {
      $.wait("400ms");
      line3.animate(
        { opacity: 0, position: [0.3, 0.7] },
        { opacity: 1, position: [0.5, 0.7] },
        { duration: "800ms", easing: "easeOut" }
      );
    }
  ]);
  $.wait("3s");
  $.parallel([
    () => {
      line1.fadeOut("500ms");
    },
    () => {
      line2.fadeOut("500ms");
    },
    () => {
      line3.fadeOut("500ms");
    }
  ]);
  $.wait("500ms");
  return $;
}
if (typeof window === "undefined") {
  await createProject5().renderVideo({
    outputType: "file",
    output: "./05-parallel-animations.mp4",
    verbose: true
  });
  console.log("Done \u2192 examples/05-parallel-animations.mp4");
}

// examples/08-transitions.ts
function createProject6() {
  const $ = new VideoFlow({
    name: "Transitions",
    width: 1920,
    height: 1080,
    fps: 30,
    backgroundColor: "#101018"
  });
  $.addImage(
    { fit: "cover", opacity: 0.45 },
    {
      source: "sample.jpg",
      startTime: 0,
      sourceDuration: 6,
      transitionIn: { transition: "zoom", duration: "1s", params: { from: 0.9 } },
      transitionOut: { transition: "fade", duration: "1s" }
    }
  );
  $.addText(
    {
      text: "Transitions",
      fontSize: 3,
      fontWeight: 800,
      color: "#ffffff"
    },
    {
      startTime: 0.5,
      sourceDuration: 4,
      transitionIn: { transition: "riseFade", duration: "700ms", params: { distance: 0.12 } },
      transitionOut: { transition: "blur", duration: "800ms", params: { amount: 10 } }
    }
  );
  $.addText(
    {
      text: "Built-in presets, no manual keyframes",
      fontSize: 1.3,
      fontWeight: 500,
      color: "#b9c2d0",
      position: [0.5, 0.6]
    },
    {
      startTime: 1,
      sourceDuration: 3.5,
      transitionIn: { transition: "slideLeft", duration: "600ms", params: { distance: 0.1 } },
      transitionOut: { transition: "slideRight", duration: "600ms", params: { distance: 0.1 } }
    }
  );
  $.wait("6s");
  return $;
}
if (typeof window === "undefined") {
  await createProject6().renderVideo({
    outputType: "file",
    output: "./08-transitions.mp4",
    verbose: true
  });
  console.log("Done \u2192 examples/08-transitions.mp4");
}

// examples/09-effects.ts
function createProject7() {
  const $ = new VideoFlow({
    name: "Effects",
    width: 1920,
    height: 1080,
    fps: 30,
    backgroundColor: "#000000"
  });
  const img = $.addImage(
    {
      fit: "cover",
      effects: [
        { effect: "pixelate", params: { size: 48 } },
        { effect: "chromaticAberration", params: { amount: 4e-3 } },
        { effect: "vignette", params: { strength: 0.7, radius: 0.75 } }
      ]
    },
    { source: "sample.jpg", startTime: 0, sourceDuration: 4 }
  );
  img.animate(
    {},
    { "effects.pixelate.size": 1 },
    { duration: "1.5s", wait: false }
  );
  const text = $.addText(
    {
      text: "GLSL Effects",
      fontSize: 5,
      fontFamily: "Rubik Storm",
      fontWeight: 800,
      color: "#ffffff",
      effects: [
        { effect: "pixelate", params: { size: 15 } }
      ]
    },
    {
      startTime: 0.5,
      sourceDuration: 3,
      transitionIn: { transition: "fade", duration: "400ms" },
      transitionOut: { transition: "fade", duration: "400ms" }
    }
  );
  text.animate(
    { "effects.pixelate.size": 15 },
    { "effects.pixelate.size": 1 },
    { duration: "1s", wait: false, easing: "ease-out" }
  );
  $.wait("4s");
  return $;
}
if (typeof window === "undefined") {
  await createProject7().renderVideo({
    outputType: "file",
    output: "./09-effects.mp4",
    verbose: true
  });
  console.log("Done \u2192 examples/09-effects.mp4");
}

// examples/web-player/player.ts
var EXAMPLES = {
  "01 \u2014 Basic Text": createProject,
  "02 \u2014 Image Background": createProject2,
  "03 \u2014 Video with Audio": createProject3,
  "04 \u2014 Captions": createProject4,
  "05 \u2014 Parallel Animations": createProject5,
  "08 \u2014 Transitions": createProject6,
  "09 \u2014 Effects": createProject7
};
var $status = document.getElementById("status");
var $player = document.getElementById("player");
var $btnPlay = document.getElementById("btn-play");
var $btnStop = document.getElementById("btn-stop");
var $seek = document.getElementById("seek");
var $time = document.getElementById("time");
var $fps = document.getElementById("fps-display");
var $select = document.getElementById("example-select");
var $btnDownload = document.getElementById("btn-download");
var $exportModal = document.getElementById("export-modal");
var $exportTitle = document.getElementById("export-title");
var $exportProgressBar = document.getElementById("export-progress-bar");
var $exportProgressText = document.getElementById("export-progress-text");
var $exportCancel = document.getElementById("export-cancel");
var renderer = null;
var currentVideoJSON = null;
async function loadExample(name) {
  const factory = EXAMPLES[name];
  if (!factory) return;
  if (renderer) {
    renderer.stop();
    renderer.destroy();
  }
  $btnPlay.textContent = "Play";
  $btnPlay.classList.remove("active");
  $fps.textContent = "";
  try {
    $status.textContent = "Compiling...";
    const $ = factory();
    const videoJSON = await $.compile();
    console.log("Compiled VideoJSON:", videoJSON);
    currentVideoJSON = videoJSON;
    $status.textContent = "Loading...";
    renderer = new DomRenderer($player);
    renderer.onFrame = () => {
      if (!seeking) {
        $seek.value = String(renderer.currentFrame);
        updateTimeDisplay();
      }
    };
    await renderer.loadVideo(videoJSON);
    $seek.max = String(renderer.totalFrames - 1);
    $seek.value = "0";
    updateTimeDisplay();
    $status.textContent = "Ready";
  } catch (e) {
    console.error(e);
    $status.textContent = `Error: ${e}`;
  }
}
var seeking = false;
$btnPlay.addEventListener("click", togglePlayback);
async function togglePlayback() {
  if (!renderer) return;
  if (renderer.playing) {
    renderer.stop();
    $btnPlay.textContent = "Play";
    $btnPlay.classList.remove("active");
  } else {
    $btnPlay.textContent = "Pause";
    $btnPlay.classList.add("active");
    await renderer.play({
      fpsCallback: (fps) => {
        $fps.textContent = `${Math.min(60, Math.round(fps))} fps`;
      }
    });
    $btnPlay.textContent = "Play";
    $btnPlay.classList.remove("active");
  }
}
$btnStop.addEventListener("click", () => {
  if (!renderer) return;
  renderer.stop();
  $btnPlay.textContent = "Play";
  $btnPlay.classList.remove("active");
  renderer.renderFrame(0);
  $seek.value = "0";
  updateTimeDisplay();
  $fps.textContent = "";
});
document.addEventListener("keydown", (e) => {
  if (e.code === "Space") {
    e.preventDefault();
    togglePlayback();
  } else if (e.code === "ArrowLeft" || e.code === "ArrowRight") {
    if (!renderer) return;
    e.preventDefault();
    if (renderer.playing) {
      renderer.stop();
      $btnPlay.textContent = "Play";
      $btnPlay.classList.remove("active");
    }
    const total = renderer.totalFrames;
    if (total === 0) return;
    const delta = e.code === "ArrowRight" ? 1 : -1;
    const next = ((renderer.currentFrame + delta) % total + total) % total;
    renderer.renderFrame(next);
    $seek.value = String(next);
    updateTimeDisplay();
  }
});
var wasPlayingBeforeSeek = false;
$seek.addEventListener("pointerdown", () => {
  if (!renderer) return;
  seeking = true;
  wasPlayingBeforeSeek = renderer.playing;
  if (wasPlayingBeforeSeek) renderer.stop();
});
$seek.addEventListener("input", () => {
  if (!renderer) return;
  seeking = true;
  renderer.renderFrame(parseInt($seek.value, 10));
  updateTimeDisplay();
});
$seek.addEventListener("change", () => {
  seeking = false;
  if (wasPlayingBeforeSeek && renderer && !renderer.playing) {
    wasPlayingBeforeSeek = false;
    renderer.play({
      fpsCallback: (fps) => {
        $fps.textContent = `${Math.min(60, Math.round(fps))} fps`;
      }
    });
  }
});
$select.addEventListener("change", () => {
  loadExample($select.value);
});
var exportAbortController = null;
$btnDownload.addEventListener("click", startExport);
$exportCancel.addEventListener("click", cancelExport);
$exportModal.addEventListener("click", (e) => {
  if (e.target === $exportModal) cancelExport();
});
async function startExport() {
  if (!currentVideoJSON) return;
  if (renderer?.playing) {
    renderer.stop();
    $btnPlay.textContent = "Play";
    $btnPlay.classList.remove("active");
  }
  exportAbortController = new AbortController();
  $exportModal.hidden = false;
  $exportTitle.textContent = "Exporting video\u2026";
  $exportProgressBar.style.width = "0%";
  $exportProgressText.textContent = "0%";
  $exportCancel.textContent = "Cancel";
  try {
    const blob = await BrowserRenderer.render(currentVideoJSON, {
      signal: exportAbortController.signal,
      onProgress: (progress) => {
        const pct = Math.round(progress * 100);
        $exportProgressBar.style.width = `${pct}%`;
        $exportProgressText.textContent = `${pct}%`;
      }
    });
    const url2 = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url2;
    a.download = `${$select.value.replace(/[^a-zA-Z0-9-_ ]/g, "")}.mp4`;
    a.click();
    URL.revokeObjectURL(url2);
    $exportTitle.textContent = "Export complete!";
    $exportProgressBar.style.width = "100%";
    $exportProgressText.textContent = "100%";
    $exportCancel.textContent = "Close";
  } catch (err) {
    if (err.name === "AbortError" || exportAbortController.signal.aborted) {
      return;
    }
    $exportTitle.textContent = "Export failed";
    $exportProgressText.textContent = String(err.message || err);
    $exportCancel.textContent = "Close";
    console.error("Export error:", err);
  }
}
function cancelExport() {
  if (exportAbortController) {
    exportAbortController.abort();
    exportAbortController = null;
  }
  $exportModal.hidden = true;
}
function updateTimeDisplay() {
  if (!renderer) return;
  const current = formatTime2(renderer.currentTime);
  const total = formatTime2(renderer.duration);
  $time.textContent = `${current} / ${total}`;
}
function formatTime2(seconds) {
  const m = Math.floor(seconds / 60);
  const s = seconds % 60;
  return `${m}:${s.toFixed(1).padStart(4, "0")}`;
}
for (const name of Object.keys(EXAMPLES)) {
  const opt = document.createElement("option");
  opt.value = name;
  opt.textContent = name;
  $select.appendChild(opt);
}
loadExample(Object.keys(EXAMPLES)[0]);
